def make_bulk():
    out = []
    for brand, name, gender, notes, accord, season in BULK_TEMPLATE:
        top = notes[:2] if len(notes) >= 2 else [notes[0], "Bergamot"]
        mid = notes[1:3] if len(notes) >= 3 else ["Jasmine", "Rose"]
        base = ["Sandalwood", "Musk", "Vanilla"]
        out.append({
            "brand": brand, "name": name, "gender": gender,
            "notes": {"top": top[:2], "middle": mid[:3], "base": base},
            "accords": [accord, "fresh", "floral", "woody"],
            "longevity": "moderate", "sillage": "moderate",
            "season": [season, "spring", "summer"] if season in ["spring","summer"] else [season, "fall", "winter"],
            "rating": round(3.5 + (hash(name) % 50) / 100, 2),
            "short_description": f"{name} by {brand}. {accord} fragrance. Popular.",
            "year": 2000 + (hash(name) % 24)
        })
    return out

def main():
    base = Path(__file__).parent.parent
    json_path = base / "data" / "perfumes_to_add.json"
    
    existing = []
    if json_path.exists():
        with open(json_path, "r", encoding="utf-8") as f:
            existing = json.load(f)
    
    existing_keys = {(p["brand"].lower(), p["name"].lower()) for p in existing}
    added = 0
    all_new = ICONIC_PERFUMES + PERFUMES + make_bulk()
    for p in all_new:
        key = (p["brand"].lower(), p["name"].lower())
        if key not in existing_keys:
            existing.append(p)
            existing_keys.add(key)
            added += 1
    
    with open(json_path, "w", encoding="utf-8") as f:
        json.dump(existing, f, indent=2, ensure_ascii=False)
    
    print(f"OK - perfumes_to_add.json: {len(existing)} parfum (yeni: {added})")

if __name__ == "__main__":
    main()
